package com.companionlink.servlet;
import com.companionlink.dao.UserDAO; import com.companionlink.model.User; import com.companionlink.util.*;
import jakarta.servlet.*; import jakarta.servlet.annotation.WebServlet; import jakarta.servlet.http.*; import java.io.IOException;
@WebServlet("/profile") public class ProfileServlet extends BaseServlet {
 private final UserDAO dao=new UserDAO();
 protected void doGet(HttpServletRequest r,HttpServletResponse h)throws ServletException,IOException{forward(r,h,"common/profile");}
 protected void doPost(HttpServletRequest r,HttpServletResponse h)throws ServletException,IOException{User u=currentUser(r);try{if("password".equals(r.getParameter("action"))){if(!PasswordUtils.matches(r.getParameter("oldPassword"),u.getPasswordHash()))throw new IllegalArgumentException("Current password is incorrect."); if(!ValidationUtils.isStrongPassword(r.getParameter("newPassword")))throw new IllegalArgumentException("New password must contain letters and numbers."); dao.updatePassword(u.getId(),r.getParameter("newPassword")); ok(r,h,"/profile","Password updated."); return;} if(!ValidationUtils.isAlphaSpaceName(r.getParameter("fullName")))throw new IllegalArgumentException("Full name must contain alphabets and spaces only."); u.setFullName(r.getParameter("fullName"));u.setPhone(r.getParameter("phone"));u.setAddress(r.getParameter("address"));u.setHealthNotes(r.getParameter("healthNotes"));u.setEmergencyContact(r.getParameter("emergencyContact"));u.setBio(r.getParameter("bio"));u.setSkills(r.getParameter("skills"));u.setAvailability(r.getParameter("availability"));dao.updateProfile(u);r.getSession().setAttribute("currentUser",dao.findById(u.getId()));ok(r,h,"/profile","Profile updated.");}catch(Exception e){r.setAttribute("error",e.getMessage());forward(r,h,"common/profile");}}
}
